SELECT count(*) FROM facet_sql_review WHERE brand_id=7 AND color_id=1 LIMIT 0 FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC; SHOW META LIKE 'multiplier';
SELECT count(*) FROM facet_sql_review WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='strict' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC; SHOW META LIKE 'multiplier';


SELECT count(*) FROM facet_sql_review WHERE brand_id=7 AND color_id=1 AND size_id=10 LIMIT 0 OPTION facet_filter_mode='auto' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC; SHOW META LIKE 'multiplier';


SELECT count(*) FROM facet_sql_review WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC; SHOW META LIKE 'multiplier';


